import{_ as e,o as a,c as i,a3 as r}from"./chunks/framework.LBeL10WQ.js";const m=JSON.parse('{"title":"Quick Start — Advertisers","description":"","frontmatter":{"title":"Quick Start — Advertisers"},"headers":[],"relativePath":"en/advertisers/onboarding-quick-start.md","filePath":"en/advertisers/onboarding-quick-start.md"}'),o={name:"en/advertisers/onboarding-quick-start.md"};function n(s,t,l,c,d,u){return a(),i("div",null,[...t[0]||(t[0]=[r('<h1 id="quick-start-—-advertisers" tabindex="-1">Quick Start — Advertisers <a class="header-anchor" href="#quick-start-—-advertisers" aria-label="Permalink to &quot;Quick Start — Advertisers&quot;">​</a></h1><p>You want to launch your first campaign on getinside. In 4 steps (15 minutes), you have a campaign running.</p><div class="tip custom-block"><p class="custom-block-title">TIP</p><p><strong>This guide is for you if:</strong> you have a getinside account (or are creating one) and want to launch your first campaign quickly.</p></div><hr><h2 id="step-1-—-create-your-account-3-min" tabindex="-1">Step 1 — Create your account (3 min) <a class="header-anchor" href="#step-1-—-create-your-account-3-min" aria-label="Permalink to &quot;Step 1 — Create your account (3 min)&quot;">​</a></h2><p>Access is <strong>reserved for professionals</strong> (company ID required).</p><ol><li>Go to <a href="https://app.getinside.media/" target="_blank" rel="noreferrer">app.getinside.media</a></li><li>Click on <strong>&quot;Create an account&quot;</strong></li><li>Enter your information: name, email, company ID, billing details</li><li>Validate your email → your account is activated</li></ol><blockquote><p>If you were invited by your account manager, open the invitation email and click the activation link.</p></blockquote><hr><h2 id="step-2-—-choose-your-format-2-min" tabindex="-1">Step 2 — Choose your format (2 min) <a class="header-anchor" href="#step-2-—-choose-your-format-2-min" aria-label="Permalink to &quot;Step 2 — Choose your format (2 min)&quot;">​</a></h2><p>Each format targets a different goal:</p><table tabindex="0"><thead><tr><th>Format</th><th>Ideal Goal</th><th>Typical Timeline</th></tr></thead><tbody><tr><td><strong>📦 Parcel Insert</strong></td><td>Physical acquisition, awareness, offline→online traffic</td><td>2-4 weeks</td></tr><tr><td><strong>📧 Dedicated Emailing</strong></td><td>Email acquisition, direct traffic</td><td>1-2 weeks</td></tr><tr><td><strong>📩 Display Email</strong></td><td>Visibility, remarketing</td><td>1 week</td></tr><tr><td><strong>📱 Social Ads</strong></td><td>Engagement, social media visibility</td><td>1-2 weeks</td></tr><tr><td><strong>🎁 Contest</strong></td><td>Qualified lead collection</td><td>2-3 weeks</td></tr></tbody></table><blockquote><p>Not sure? Your getinside account manager advises you based on your goals during a 15-minute call.</p></blockquote><hr><h2 id="step-3-—-submit-your-brief-5-min" tabindex="-1">Step 3 — Submit your brief (5 min) <a class="header-anchor" href="#step-3-—-submit-your-brief-5-min" aria-label="Permalink to &quot;Step 3 — Submit your brief (5 min)&quot;">​</a></h2><p><strong>Workspace:</strong> My Campaigns → Create a campaign</p><p>You will need:</p><p><strong>Basic information:</strong></p><ul><li>Desired volume (number of parcels, contacts, impressions depending on format)</li><li>Budget and broadcast dates</li><li>Destination URL (with UTM if possible)</li></ul><p><strong>Creative material:</strong></p><ul><li>The promise of your offer (e.g., &quot;-20% for new customers&quot;)</li><li>Your visuals (according to <a href="/handbook/en/advertisers/sponsored-mail/design-guide/print-specs.html">technical specifications</a>)</li><li>Your key arguments</li></ul><blockquote><p>No visuals? The <strong>getinside Studio</strong> creates your creative assets. Contact your manager to learn more.</p></blockquote><hr><h2 id="step-4-—-select-your-distributors-and-validate-5-min" tabindex="-1">Step 4 — Select your distributors and validate (5 min) <a class="header-anchor" href="#step-4-—-select-your-distributors-and-validate-5-min" aria-label="Permalink to &quot;Step 4 — Select your distributors and validate (5 min)&quot;">​</a></h2><ol><li>The platform offers you a <strong>selection of distributors</strong> whose audience matches your criteria</li><li>View profiles: sector, average basket, weekly volume</li><li>Distributors receive your proposal and can <strong>accept, refuse or counter-propose</strong></li><li>Once agreement is reached, <strong>validate the campaign in less than 48 business hours</strong> → a Purchase Order is automatically generated</li><li>Validate the <strong>Proof (BAT)</strong> — final visual and technical check before going into production</li></ol><hr><h2 id="your-campaign-is-launched-✅" tabindex="-1">Your campaign is launched ✅ <a class="header-anchor" href="#your-campaign-is-launched-✅" aria-label="Permalink to &quot;Your campaign is launched ✅&quot;">​</a></h2><p>Track performance in real-time in <strong>My Campaigns → Statistics</strong>.</p><p><strong>Important reminder:</strong> Validation within 48h is contractual — after this period, the campaign may be canceled and fees may apply.</p><hr><p><strong>Next steps:</strong></p><ul><li><a href="/handbook/en/advertisers/sponsored-mail/">Parcel Insert Guide</a> — technical and creative specs</li><li><a href="/handbook/en/advertisers/pricing.html">Pricing &amp; Offers</a> — rates and service levels</li><li><a href="/handbook/en/resources/studio.html">Creative Studio</a> — delegate the creation of your materials</li></ul>',32)])])}const h=e(o,[["render",n]]);export{m as __pageData,h as default};
